onClick:
{{
  (async () => {
    // 1. Kiểm tra mật khẩu quản lý (thay "888888" bằng mật khẩu bạn muốn)
    const pass = inp_MatKhauXoa.text;
    if (pass !== "Admin") {
      return showAlert("❌ Mật khẩu sai! Lệnh hủy toàn bộ bị từ chối.", "error");
    }

    try {
      // 2. Chạy Query Xóa TOÀN BỘ (không cần truyền id nữa)
      await Action_Delete_Scrap.run();

      // 3. Làm mới bảng danh sách phế để hiển thị bảng trống
      await Get_Scrap_List.run({ ignoreCache: true });

      // 4. Đóng Modal và làm sạch ô mật khẩu
      closeModal("Modal_XacNhanXoa");
      inp_MatKhauXoa.setValue("");

      showAlert("✅ ĐÃ XÓA SẠCH TOÀN BỘ DỮ LIỆU BÁO PHẾ!", "success");

    } catch (err) {
      console.error("Lỗi:", err);
      showAlert("❌ Lỗi hệ thống: " + err.message, "error");
    }
  })()
}}
